});
var edtNarabi = (function(raceNo, nInfo){
if(!nInfo){
return;
}
for(var i = 0; i < nInfo.length; i++){
var syaban = '<span class="slsnum16 base_color_' + nInfo[i].syaban + '">' + nInfo[i].syaban + '</span>';
