function rafuncKeirinjoASC(a,b){
if (a[3] < b[3]) return 1;
if (a[3] > b[3]) return -1;
if (a[3] == b[3]){ 
if (a[22] < b[22]) return -1;
if (a[22] > b[22]) return 1;
}
return 0;
};
function rafuncKeirinjoDesc(a,b){
if (a[3] < b[3]) return -1;
if (a[3] > b[3]) return 1;
if (a[3] == b[3]){ 
if (a[22] < b[22]) return 1;
if (a[22] > b[22]) return -1;
}
return 0;
};
function rafuncDentouASC(a,b){
if (a[2] < b[2]) return -1;
